            for (int j = 1; j <= n; ++j) {
                d[i][j] = min(d[i][j], d[i][k] + d[k][j]);
            }
        }
    }
    cout << (d[1][n] >= INF / 2 ? -1 : d[1][n]) << '\n';
}


