        } else {
            int l, r;
            cin >> l >> r;
            long long ans = 0;
            while (l <= r && l % B) ans += a[l++];
            while (l + B - 1 <= r) ans += block[l / B], l += B;
            while (l <= r) ans += a[l++];
            cout << ans << '\n';
        }
    }
}


