bool check(vector<int> &a, int mid, int k) {
    int need = 1, last = a[0];
    for (int i = 1; i < (int)a.size(); ++i) {
        if (a[i] - last >= mid) {
            ++need;
            last = a[i];
        }
    }
    return need >= k;
}
void solve() {
    int n, k;
    cin >> n >> k;
    vector<int> a(n);
    for (int &x : a) cin >> x;
    sort(all(a));
    int l = 0, r = (int)2e9, ans = 0;
    while (l <= r) {
        int mid = (l + r) >> 1;
        if (check(a, mid, k)) ans = mid, l = mid + 1;
        else r = mid - 1;
    }
    cout << ans << '\n';
}


